    readonly ChatBskyConvoGetUnreadCounts: {
        readonly lexicon: 1;
        readonly id: 'chat.bsky.convo.getUnreadCounts';
        readonly defs: {
            readonly main: {
                readonly type: 'query';
                readonly description: "[NOTE: This is under active development and should be considered unstable while this note is here]. Returns unread conversation counts for conversations that are unlocked, not muted, split by convo status. Direct convos are excluded when a block relationship exists between the actor and the other member, or when the other member's account is deleted or deactivated. Group convos are considered unread if they have unread join request counts.";
                readonly parameters: {
                    readonly type: 'params';
                    readonly properties: {
                        readonly includeGroupChats: {
                            readonly type: 'boolean';
                            readonly default: true;
                            readonly description: 'When false, group convos are excluded from the counts.';
                        };
                    };
                };
                readonly output: {
                    readonly encoding: 'application/json';
                    readonly schema: {
                        readonly type: 'object';
                        readonly required: ["unreadAcceptedConvos", "unreadRequestConvos"];
                        readonly properties: {
                            readonly unreadAcceptedConvos: {
                                readonly type: 'integer';
                                readonly description: 'Number of unread, unlocked accepted convos. Counts convos with unread messages and unread join requests. Capped at 31, where 31 means more than 30.';
                            };
                            readonly unreadRequestConvos: {
                                readonly type: 'integer';
                                readonly description: 'Number of unread, unlocked request convos. Includes convos with unread messages, but not with unread join request, since only the owner of a group has join requests to read, and the group would necessarily be accepted. Capped at 11, where 11 means more than 10.';
                            };
                        };
                    };
                };
            };
        };
    };
    readonly ChatBskyConvoLeaveConvo: {
        readonly lexicon: 1;
        readonly id: 'chat.bsky.convo.leaveConvo';
        readonly defs: {
            readonly main: {
                readonly type: 'procedure';
                readonly description: 'Leaves a conversation (direct or group). For group, this effectively removes membership. For direct, membership is never removed, only changed to remove from enumerations by the user who left.';
                readonly errors: [{
                    readonly name: 'InvalidConvo';
                }, {
                    readonly name: 'OwnerCannotLeave';
                    readonly description: 'The owner of a group conversation cannot leave before locking the group.';
                }];
                readonly input: {
                    readonly encoding: 'application/json';
                    readonly schema: {
                        readonly type: 'object';
                        readonly required: ["convoId"];
                        readonly properties: {
                            readonly convoId: {
                                readonly type: 'string';
                            };
                        };
                    };
                };
                readonly output: {
                    readonly encoding: 'application/json';
                    readonly schema: {
                        readonly type: 'object';
                        readonly required: ["convoId", "rev"];
                        readonly properties: {
                            readonly convoId: {
                                readonly type: 'string';
                            };
                            readonly rev: {
                                readonly type: 'string';
                            };
                        };
                    };
                };
            };
        };
    };
