    readonly ChatBskyGroupCreateGroup: {
        readonly lexicon: 1;
        readonly id: 'chat.bsky.group.createGroup';
        readonly defs: {
            readonly main: {
                readonly type: 'procedure';
                readonly description: "[NOTE: This is under active development and should be considered unstable while this note is here]. Creates a group convo, specifying the members to be added to it. Unlike getConvoForMembers, this isn't idempotent. It will create new groups even if the membership is identical to pre-existing groups. Will create 'request' membership for all members, except the owner who is 'accepted'.";
                readonly errors: [{
                    readonly name: 'AccountSuspended';
                }, {
                    readonly name: 'BlockedActor';
                }, {
                    readonly name: 'BlockedSubject';
                }, {
                    readonly name: 'NewAccountCannotCreateGroup';
                }, {
                    readonly name: 'NotFollowedBySender';
                }, {
                    readonly name: 'RecipientNotFound';
                }, {
                    readonly name: 'UserForbidsGroups';
                }];
                readonly input: {
                    readonly encoding: 'application/json';
                    readonly schema: {
                        readonly type: 'object';
                        readonly required: ["members", "name"];
                        readonly properties: {
                            readonly members: {
                                readonly type: 'array';
                                readonly maxLength: 49;
                                readonly items: {
                                    readonly type: 'string';
                                    readonly format: 'did';
                                };
                            };
                            readonly name: {
                                readonly type: 'string';
                                readonly minLength: 1;
                                readonly maxGraphemes: 50;
                                readonly maxLength: 500;
                            };
                        };
                    };
                };
                readonly output: {
                    readonly encoding: 'application/json';
                    readonly schema: {
                        readonly type: 'object';
                        readonly required: ["convo"];
                        readonly properties: {
                            readonly convo: {
                                readonly type: 'ref';
                                readonly ref: 'lex:chat.bsky.convo.defs#convoView';
                            };
                        };
                    };
                };
            };
        };
    };
