    readonly ToolsOzoneReportAssignModerator: {
        readonly lexicon: 1;
        readonly id: 'tools.ozone.report.assignModerator';
        readonly defs: {
            readonly main: {
                readonly type: 'procedure';
                readonly description: 'Assign a report to a user. Defaults to the caller. Admins may assign to any moderator.';
                readonly input: {
                    readonly encoding: 'application/json';
                    readonly schema: {
                        readonly type: 'object';
                        readonly required: ["reportId"];
                        readonly properties: {
                            readonly reportId: {
                                readonly type: 'integer';
                                readonly description: 'The ID of the report to assign.';
                            };
                            readonly queueId: {
                                readonly type: 'integer';
                                readonly description: 'Optional queue ID to associate the assignment with. If not provided and the report has been assigned on a queue before, it will stay on that queue.';
                            };
                            readonly did: {
                                readonly type: 'string';
                                readonly format: 'did';
                                readonly description: "DID to be assigned. Defaults to the caller's DID. Admins may assign to any moderator.";
                            };
                            readonly isPermanent: {
                                readonly type: 'boolean';
                                readonly description: 'When true, the assignment has no expiry (endAt is null). Throws AlreadyAssigned if another user already has a permanent assignment on this report.';
                            };
                        };
                    };
                };
                readonly output: {
                    readonly encoding: 'application/json';
                    readonly schema: {
                        readonly type: 'ref';
                        readonly ref: 'lex:tools.ozone.report.defs#assignmentView';
                    };
                };
                readonly errors: [{
                    readonly name: 'AlreadyAssigned';
                    readonly description: 'The report is already assigned to another user.';
                }, {
                    readonly name: 'InvalidAssignment';
                    readonly description: 'The report ID or queue ID is invalid.';
                }];
            };
        };
    };
    readonly ToolsOzoneReportCreateActivity: {
        readonly lexicon: 1;
        readonly id: 'tools.ozone.report.createActivity';
        readonly defs: {
            readonly main: {
                readonly type: 'procedure';
                readonly description: 'Register an activity on a report. For state-change activity types, validates the transition and updates report.status atomically.';
                readonly input: {
                    readonly encoding: 'application/json';
                    readonly schema: {
                        readonly type: 'object';
                        readonly required: ["reportId", "activity"];
                        readonly properties: {
                            readonly reportId: {
                                readonly type: 'integer';
                                readonly description: 'ID of the report to record activity on';
                            };
                            readonly activity: {
                                readonly type: 'union';
                                readonly refs: ["lex:tools.ozone.report.defs#queueActivity", "lex:tools.ozone.report.defs#assignmentActivity", "lex:tools.ozone.report.defs#escalationActivity", "lex:tools.ozone.report.defs#closeActivity", "lex:tools.ozone.report.defs#reopenActivity", "lex:tools.ozone.report.defs#noteActivity"];
                                readonly description: 'The type of activity to record.';
                            };
                            readonly internalNote: {
                                readonly type: 'string';
                                readonly description: 'Optional moderator-only note. Not visible to reporters.';
                            };
                            readonly publicNote: {
                                readonly type: 'string';
                                readonly description: 'Optional public-facing note, potentially visible to the reporter.';
                            };
                            readonly isAutomated: {
                                readonly type: 'boolean';
                                readonly description: 'Set true when this activity is triggered by an automated process. Defaults to false.';
                                readonly default: false;
                            };
                        };
                    };
                };
                readonly output: {
                    readonly encoding: 'application/json';
                    readonly schema: {
                        readonly type: 'object';
                        readonly required: ["activity"];
                        readonly properties: {
                            readonly activity: {
                                readonly type: 'ref';
                                readonly ref: 'lex:tools.ozone.report.defs#reportActivityView';
                            };
                        };
                    };
                };
                readonly errors: [{
                    readonly name: 'ReportNotFound';
                    readonly description: 'No report exists with the given reportId';
                }, {
                    readonly name: 'InvalidStateTransition';
                    readonly description: "The requested state transition is not permitted from the report's current status";
                }, {
                    readonly name: 'AlreadyInTargetState';
                    readonly description: 'The report is already in the status implied by this activity type';
                }];
            };
        };
    };
