    readonly id: 'tools.ozone.report.queryReports';
    readonly defs: {
        readonly main: {
            readonly type: 'query';
            readonly description: 'View moderation reports. Reports are individual instances of content being reported, as opposed to subject statuses which aggregate reports at the subject level.';
            readonly parameters: {
                readonly type: 'params';
                readonly required: ["status"];
                readonly properties: {
                    readonly queueId: {
                        readonly type: 'integer';
                        readonly description: 'Filter by queue ID. Use -1 for unassigned reports.';
                    };
                    readonly reportTypes: {
                        readonly type: 'array';
                        readonly items: {
                            readonly type: 'string';
                        };
                        readonly description: 'Filter by report types (fully qualified string in the format of com.atproto.moderation.defs#reason<name>).';
                    };
                    readonly status: {
                        readonly type: 'string';
                        readonly knownValues: ["open", "closed", "escalated", "queued", "assigned"];
                        readonly description: 'Filter by report status.';
                    };
                    readonly subject: {
                        readonly type: 'string';
                        readonly format: 'uri';
                        readonly description: 'Filter by subject DID or AT-URI.';
                    };
                    readonly did: {
                        readonly type: 'string';
                        readonly format: 'did';
                        readonly description: 'Filter to reports where the subject is this DID or any record owned by this DID. Unlike `subject` (which scopes to a specific account or record), this returns all reports tied to the DID across both account-level and record-level subjects.';
                    };
                    readonly subjectType: {
                        readonly type: 'string';
                        readonly description: 'If specified, reports of the given type (account or record) will be returned.';
                        readonly knownValues: ["account", "record"];
                    };
                    readonly collections: {
                        readonly type: 'array';
                        readonly maxLength: 20;
                        readonly description: "If specified, reports where the subject belongs to the given collections will be returned. When subjectType is set to 'account', this will be ignored.";
                        readonly items: {
                            readonly type: 'string';
                            readonly format: 'nsid';
                        };
                    };
                    readonly reportedAfter: {
                        readonly type: 'string';
                        readonly format: 'datetime';
                        readonly description: 'Retrieve reports created after a given timestamp';
                    };
                    readonly reportedBefore: {
                        readonly type: 'string';
                        readonly format: 'datetime';
                        readonly description: 'Retrieve reports created before a given timestamp';
                    };
                    readonly isMuted: {
                        readonly type: 'boolean';
                        readonly default: false;
                        readonly description: 'Filter by muted status. true returns only muted reports, false returns only unmuted reports. Defaults to false.';
                    };
                    readonly assignedTo: {
                        readonly type: 'string';
                        readonly format: 'did';
                        readonly description: 'Filter by the DID of the moderator permanently assigned to the report.';
                    };
                    readonly sortField: {
                        readonly type: 'string';
                        readonly default: 'createdAt';
                        readonly enum: ["createdAt", "updatedAt"];
                    };
                    readonly sortDirection: {
                        readonly type: 'string';
                        readonly default: 'desc';
                        readonly enum: ["asc", "desc"];
                    };
                    readonly limit: {
                        readonly type: 'integer';
                        readonly minimum: 1;
                        readonly maximum: 100;
                        readonly default: 50;
                    };
                    readonly cursor: {
                        readonly type: 'string';
                    };
                };
            };
            readonly output: {
                readonly encoding: 'application/json';
                readonly schema: {
                    readonly type: 'object';
                    readonly required: ["reports"];
                    readonly properties: {
                        readonly cursor: {
                            readonly type: 'string';
                        };
                        readonly reports: {
                            readonly type: 'array';
                            readonly items: {
                                readonly type: 'ref';
                                readonly ref: 'lex:tools.ozone.report.defs#reportView';
                            };
                        };
                    };
                };
            };
        };
    };
